-- Tags: no-fasttest
-- no-fasttest: requires the ORC input format, which is not built in fasttest.

-- Regression test for https://github.com/ClickHouse/ClickHouse/issues/109295
-- The native ORC reader (input_format_orc_use_fast_decoder=1, default) used to convert every timestamp
-- through a fixed DateTime64(9) intermediate (seconds * 1e9 + nanoseconds). A timestamp beyond ~year 2262
-- overflows Int64 at nanosecond scale and was rejected, even when the requested DateTime64 scale can hold
-- the value (e.g. DateTime64(6), as produced by Iceberg). Now the reader converts directly at the requested
-- scale and only consults date_time_overflow_behavior when even the target scale does not fit Int64.
--
-- The blob below is a single-row ORC file with one column c0 DateTime64(6) whose value is
-- reinterpret(124634473119644360::Int64, 'DateTime64(6)') (raw 124634473119644360 microseconds, ~year 5919).
-- It was produced with:
--   clickhouse-local -q "SELECT reinterpret(124634473119644360::Int64,'DateTime64(6)') AS c0 FORMAT ORC" | xxd -p

SET input_format_orc_use_fast_decoder = 1;

-- Reading into the same scale as written (DateTime64(6)) now succeeds and round-trips the exact value.
SELECT reinterpret(c0, 'Int64') FROM format(ORC, 'c0 DateTime64(6)', unhex(''));

-- Reading into a coarser scale truncates toward zero, matching the DateTime64(6) -> DateTime64(N) cast.
SELECT reinterpret(c0, 'Int64') FROM format(ORC, 'c0 DateTime64(3)', unhex(''));
SELECT reinterpret(c0, 'Int64') FROM format(ORC, 'c0 DateTime64(0)', unhex(''));

-- Reading into DateTime64(9) still overflows Int64 (the value genuinely does not fit at nanosecond scale).
-- The default date_time_overflow_behavior=ignore keeps the historical behavior and throws instead of corrupting.
SELECT * FROM format(ORC, 'c0 DateTime64(9)', unhex('')); -- { serverError VALUE_IS_OUT_OF_RANGE_OF_DATA_TYPE }

SELECT * FROM format(ORC, 'c0 DateTime64(9)', unhex('')) SETTINGS date_time_overflow_behavior = 'throw'; -- { serverError VALUE_IS_OUT_OF_RANGE_OF_DATA_TYPE }

-- With saturate the out-of-range value is clamped to the Int64 range instead of throwing.
SELECT reinterpret(c0, 'Int64') FROM format(ORC, 'c0 DateTime64(9)', unhex('')) SETTINGS date_time_overflow_behavior = 'saturate';
